import { useEffect, useState } from "react";
import { useNavigate, useParams } from "react-router-dom";
import { getSaleById, updateSale } from "../../api/saleApi";
import { getAuth } from "../../utils/auth";

export default function EditSale() {
  const { id } = useParams();
  const navigate = useNavigate();

  const { role } = getAuth();
  const canManage = role === "admin" || role === "manager";

  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState("");

  const [sale, setSale] = useState(null);

  const [form, setForm] = useState({
    price: "",
    payment_status: "pending",
  });

  useEffect(() => {
    if (!canManage) {
      alert("Access denied");
      navigate("/vehicles");
      return;
    }

    const load = async () => {
      setError("");
      setLoading(true);
      try {
        const res = await getSaleById(id);
        const s = res.data;
        setSale(s);

        setForm({
          price: s.price ?? "",
          payment_status: s.payment_status || "pending",
        });
      } catch (err) {
        setError(err.response?.data?.message || "Failed to load sale");
      } finally {
        setLoading(false);
      }
    };

    load();
  }, [id, canManage, navigate]);

  const onChange = (e) => {
    const { name, value } = e.target;
    setForm((p) => ({ ...p, [name]: value }));
  };

  const submit = async (e) => {
    e.preventDefault();
    setError("");

    if (form.price === "" || Number(form.price) < 0) return setError("Price must be 0 or more");

    setSaving(true);
    try {
      await updateSale(id, {
        price: Number(form.price),
        payment_status: form.payment_status,
      });

      alert("Updated!");
      navigate("/sales");
    } catch (err) {
      setError(err.response?.data?.message || "Update failed");
    } finally {
      setSaving(false);
    }
  };

  if (loading) return <p style={{ padding: 20 }}>Loading...</p>;

  if (error && !sale) {
    return (
      <div style={{ padding: 20 }}>
        <div style={errorBox}><b>Error:</b> {error}</div>
        <button onClick={() => navigate("/sales")} style={{ marginTop: 12 }}>Back</button>
      </div>
    );
  }

  return (
    <div style={{ padding: 20, display: "flex", justifyContent: "center" }}>
      <div style={{ width: "100%", maxWidth: 720 }}>
        <div style={card}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
            <h2 style={{ margin: 0 }}>Edit Sale</h2>
            <button onClick={() => navigate("/sales")} style={btnGhost}>Back</button>
          </div>

          {/* Sale summary */}
          <div style={{ marginTop: 10, padding: 12, border: "1px solid #e5e7eb", borderRadius: 12 }}>
            <div style={{ fontSize: 14 }}>
              <b>Vehicle:</b>{" "}
              {sale?.vehicle?.brand
                ? `${sale.vehicle.brand} ${sale.vehicle.model || sale.vehicle.type || ""}`
                : "-"}
            </div>
            <div style={{ fontSize: 14, marginTop: 6 }}>
              <b>Customer:</b> {sale?.customer?.name || "-"}
            </div>
            <div style={{ fontSize: 12, opacity: 0.75, marginTop: 6 }}>
              Created: {sale?.createdAt ? new Date(sale.createdAt).toLocaleString() : "-"}
            </div>
          </div>

          {error && (
            <div style={errorBox}>
              <b>Error:</b> {error}
            </div>
          )}

          <form onSubmit={submit} style={{ marginTop: 12 }}>
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12 }}>
              <div style={fieldRow}>
                <label style={label}>Price (Rs.)</label>
                <input
                  name="price"
                  type="number"
                  min="0"
                  value={form.price}
                  onChange={onChange}
                  required
                  style={input}
                />
              </div>

              <div style={fieldRow}>
                <label style={label}>Payment Status</label>
                <select
                  name="payment_status"
                  value={form.payment_status}
                  onChange={onChange}
                  style={input}
                >
                  <option value="pending">Pending</option>
                  <option value="partial">Partial</option>
                  <option value="completed">Completed</option>
                </select>

                <div style={hint}>
                  If you set <b>completed</b>, backend will mark vehicle as <b>sold</b>.
                </div>
              </div>
            </div>

            <div style={{ display: "flex", gap: 10, marginTop: 16 }}>
              <button type="submit" style={btnPrimary} disabled={saving}>
                {saving ? "Saving..." : "Save Changes"}
              </button>
              <button type="button" style={btnGhost} onClick={() => navigate("/sales")} disabled={saving}>
                Cancel
              </button>
            </div>
          </form>
        </div>
      </div>
    </div>
  );
}

const card = {
  border: "1px solid #e5e7eb",
  borderRadius: 14,
  padding: 16,
  background: "#fff",
};
const fieldRow = { marginTop: 12 };
const label = { display: "block", marginBottom: 6, fontWeight: 600 };
const input = {
  width: "100%",
  padding: "10px 12px",
  borderRadius: 10,
  border: "1px solid #d1d5db",
  outline: "none",
};
const hint = { marginTop: 6, fontSize: 12, opacity: 0.75 };
const errorBox = {
  marginTop: 12,
  padding: 10,
  borderRadius: 10,
  border: "1px solid #fca5a5",
  background: "#fff1f2",
};
const btnPrimary = {
  padding: "10px 14px",
  borderRadius: 10,
  border: "1px solid #111827",
  background: "#111827",
  color: "#fff",
  cursor: "pointer",
};
const btnGhost = {
  padding: "10px 14px",
  borderRadius: 10,
  border: "1px solid #d1d5db",
  background: "#fff",
  cursor: "pointer",
};
